CREATE OR REPLACE FUNCTION digitaltwinapp.notify_user_created()
RETURNS TRIGGER AS $$
BEGIN
    PERFORM pg_notify(
        'user_created',
        json_build_object('user_id', NEW.user_id)::text
    );
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trg_user_created
    AFTER INSERT ON digitaltwinapp.users
    FOR EACH ROW EXECUTE FUNCTION digitaltwinapp.notify_user_created();
